import React from 'react';
import { List, ListItem, ListItemText, TextField, Typography, Box } from '@mui/material';
import { shapeDefinitions, defaultShape } from '../shapes';
import ColorPicker from './ColorPicker';

const Sidebar = ({
  selectedShape,
  onShapeSelect,
  shapeParams,
  onParamChange,
  color,
  onColorChange,
  lineWidth,
  onLineWidthChange,
  mousePos
}) => {
  return (
    <div className="sidebar">
      <Typography variant="h6" sx={{ 
        p: 2, 
        fontFamily: "'Poppins', sans-serif",
        color: '#2d3748',
        borderBottom: '1px solid #e2e8f0'
      }}>
        Shape Tools
      </Typography>
      
      <List>
        {Object.entries(shapeDefinitions).map(([key, shape]) => (
          <ListItem
            button
            key={key}
            selected={selectedShape === key}
            onClick={() => onShapeSelect(key)}
            sx={{
              fontFamily: "'Inter', sans-serif",
              '&.Mui-selected': {
                backgroundColor: '#edf2f7',
                '&:hover': {
                  backgroundColor: '#e2e8f0',
                },
              },
            }}
          >
            <ListItemText 
              primary={shape.text}
              primaryTypographyProps={{
                fontFamily: "'Inter', sans-serif",
                fontWeight: selectedShape === key ? 600 : 400,
              }}
            />
          </ListItem>
        ))}
      </List>

      {selectedShape !== defaultShape && (
        <Box sx={{ p: 2 }}>
          <Typography variant="subtitle1" sx={{ 
            mb: 2,
            fontFamily: "'Poppins', sans-serif",
            color: '#2d3748'
          }}>
            Shape Parameters
          </Typography>
          
          {shapeDefinitions[selectedShape].params.map(param => (
            <TextField
              key={param.name}
              label={param.label}
              type="number"
              value={shapeParams[param.name] || ''}
              onChange={(e) => onParamChange(param.name, e.target.value)}
              fullWidth
              margin="normal"
              size="small"
              sx={{
                '& .MuiOutlinedInput-root': {
                  fontFamily: "'Inter', sans-serif",
                },
                '& .MuiInputLabel-root': {
                  fontFamily: "'Inter', sans-serif",
                },
              }}
            />
          ))}

          <ColorPicker
            color={color}
            onColorChange={onColorChange}
            lineWidth={lineWidth}
            onLineWidthChange={onLineWidthChange}
          />

          <Box sx={{ mt: 2, p: 2, backgroundColor: '#f8f9fa', borderRadius: 2 }}>
            <Typography variant="body2" sx={{ 
              fontFamily: "'Inter', sans-serif",
              color: '#4a5568'
            }}>
              Mouse Position:
            </Typography>
            <Typography variant="body2" sx={{ 
              fontFamily: "'Inter', sans-serif",
              color: '#2d3748',
              fontWeight: 500
            }}>
              X: {mousePos.x.toFixed(0)}, Y: {mousePos.y.toFixed(0)}
            </Typography>
          </Box>
        </Box>
      )}
    </div>
  );
};

export default Sidebar;
